// This fallback is used for local development builds.
// =============================================================================

#ifndef AURA_VERSION_STRING
#  define AURA_VERSION_STRING  "1.0.0"
#endif

#ifndef AURA_VERSION_MAJOR
#  define AURA_VERSION_MAJOR   1
#endif

#ifndef AURA_VERSION_MINOR
#  define AURA_VERSION_MINOR   0
#endif

#ifndef AURA_VERSION_PATCH
#  define AURA_VERSION_PATCH   0
#endif

#ifndef AURA_BUILD_NUMBER
#  define AURA_BUILD_NUMBER    0
#endif

#ifndef AURA_BUILD_DATE
#  define AURA_BUILD_DATE      __DATE__
#endif

#ifndef AURA_GIT_COMMIT
#  define AURA_GIT_COMMIT      "dev"
#endif
